class Solution {
public:
    int countKReducibleNumbers(string s, int k) {
        long long n = stoll(s, nullptr, 2);
        int count = 0;
        for (long long i = 1; i < n; ++i) {
            int setBits = __builtin_popcount(i);
            if (k >= setBits) {
                count++;
            }
        }
        return count % (1e9 + 7);
    }
};
